<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/vendor/stadiums"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "name": "consequatur",
    "city": "consequatur",
    "address": "consequatur",
    "price_per_hour": 11613.31890586
};

fetch(url, {
    method: "POST",
    headers,
